INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (1, 'fe2c49ad940043bb883395c3bbfabf61', 'pedagogy', '✨ <b>Inter Study jurnali endi Researcher.uz platformasida!</b> ✨

<b>O''zbek tilida:</b>
Pedagogika, psixologiya va san’atshunoslik sohalaridagi tadqiqotlarni qamrab oluvchi Inter Study ilmiy jurnali maqolalari endi Researcher.uz orqali tadqiqotchilar, talabalar va o‘qituvchilar uchun ochiq tarzda taqdim etiladi. 📚 Ilmiy bilimlarga oson kirish imkoniyatidan foydalaning!

<b>На русском языке:</b>
Статьи многопрофильного научного журнала Inter Study, охватывающего исследования в области педагогики, психологии и искусствоведения, теперь открыты для широкой аудитории через Researcher.uz. 🎓 Исследователи, студенты и преподаватели, откройте для себя легкий доступ к научным знаниям!', '', true, 41, '2026-06-17 18:48:29.733153', NULL, NULL);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (2, 'fe2c49ad940043bb883395c3bbfabf61', 'psychology', '✨ <b>Psixologiya sohasidagi yangi ilmiy tadqiqotlar!</b> ✨

<b>O''zbek tilida:</b>
Inter Study jurnali endi Researcher.uz platformasida psixologiya bo''yicha yangi maqolalarni taqdim etadi. 🧠 Tadqiqotchilar, talabalar va o''qituvchilar uchun ochiq materiallar bilimingizni boyitadi.

<b>На русском языке:</b>
✨ <b>Новые научные исследования в области психологии!</b> ✨
Журнал Inter Study теперь на платформе Researcher.uz представляет новые статьи по психологии. 📚 Открытые материалы обогатят ваши знания.', '', true, 42, '2026-06-17 19:20:17.532343', NULL, NULL);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (3, 'fe2c49ad940043bb883395c3bbfabf61', 'psychology', '<b>Psixologiya fanining asoslari</b> 
Psixologiya - insonning psixik faoliyatini, shaxsning shakllanishini va rivojlanishini o‘rganuvchi fan hisoblanadi. Psixologiya sohasidagi tadqiqotlar insonning xulq-atvorini, his-tuyg‘ularini, fikr va tafakkurini, shuningdek, uning atrof-muhit bilan o‘zaro ta’sirini o‘rganadi.

<b>O''zbek tilida:</b>
Inter Study jurnali psixologiya bo''yicha maqolalarni taqdim etadi. Ushbu maqolalar psixologiya fanining turli jabhalarini, jumladan, insonning psixik faoliyatini, shaxsning shakllanishini va rivojlanishini o‘rganadi. 

<b>На русском языке:</b>
Журнал Inter Study представляет статьи по психологии. Эти статьи посвящены различным аспектам психологии, включая психическую деятельность человека, формирование и развитие личности. 

Psixologiya sohasidagi tadqiqotlar insonning psixik faoliyatini, shaxsning shakllanishini va rivojlanishini o‘rganishga qaratilgan. Bunday tadqiqotlar insonning xulq-atvorini, his-tuyg‘ularini, fikr va tafakkurini, shuningdek, uning atrof-muhit bilan o‘zaro ta’sirini o‘rganish imkonini beradi.', '', true, 43, '2026-06-17 20:11:38.776523', NULL, NULL);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (5, 'fe2c49ad940043bb883395c3bbfabf61', 'humanities', '## Humanities: Tarix, Falsafa va Filologiyaning O''zaro Bog''liqligi

Ilmiy bilimlarning turli sohalari bir-biri bilan chambarchas bog''liqdir. <b>Tarix</b>, <b>Falsafa</b> va <b>Filologiya</b> ham shunday sohalardandir. Ular bir-birini to''ldiradi va ilmiy tushunchalarimizni boyitadi.

### Tarix: O''tmishning O''rganilishi
Tarix fani o''tmishdagi voqealarni, jamiyatlarning rivojlanishini va madaniyatlarning shakllanishini o''rganadi. U bizga o''tmishdagi xatolar va yutuqlarni ko''rsatadi.

### Falsafa: Hayotning Ma''nosi
Falsafa fani esa, hayotning umumiy savollariga javob izlaydi. U mavjudlik, bilim, qiymatlar va reallik haqida fikr yuritadi.

### Filologiya: Til va Adabiyot
Filologiya tilda ifodalangan madaniyatni o''rganadi. U tilning tuzilishi, adabiyotning rivojlanishi va kommunikatsiya jarayonlarini tahlil qiladi.

### O''zaro Bog''liqlik
Ushbu uch soha bir-biri bilan chambarchas bog''liqdir. Tarixiy kontekst falsafiy qarashlar uchun zamin yaratadi. Filologiya esa, tarixiy va falsafiy matnlarni tushunishimizga yordam beradi.

Shunday qilib, <b>Tarix</b>, <b>Falsafa</b> va <b>Filologiya</b> bir-birini to''ldiruvchi va ilmiy bilish jarayonida muhim ahamiyatga ega bo''lgan sohalardir.', '', true, 44, '2026-06-17 22:37:27.251822', NULL, NULL);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (4, 'fdc71d690e2243659052473b6fc301b6', 'startup', 'Agar siz startup qurish yoki rivojlantirish bilan shug''ullansangiz, unda siz uchun qiziqarli yangilik bor! 📣

MIT universitetining startup ecosystem builderlari endi siz uchun O''zbekistonda! 🇺🇿

Ethan Pierse (Borderless Ventures), Maxime Paradis (United Founders) va Jinan Abounadi (MIT Sandbox) kabi ekspertlar bilan tanishing va ularning tajribalarini o''rganing! 💡

Ushbu tadbir sizga venture fondlari haqida bilib olish, o''z biznesingizni rivojlantirish va yangi aloqalar o''rnatish imkoniyatini beradi! 📈

Keling, ushbu imkoniyatdan foydalaning va o''z biznesingizni yangi bosqichga olib chiqing! 🚀 #startup #mit #oxunjoncommunity', NULL, true, 621, '2026-06-17 20:45:02', NULL, NULL);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (17, 'c0d93f65fc09419aafe5010873aaa10a', 'repost', '<b>Golden Gate Ventures Oʻzbekistonda ofis ochadi</b>

Golden Gate Ventures kompaniyasi Oʻzbekistonda o‘z ofisini ochishi haqida e’lon qildi. Bu haqda Toshkent xalqaro investitsiya forumida (TIIF 2026) ma’lum qilindi.

Uzbek-Oman Investment Company (UzOman) bilan hamkorlik shartnomasi imzolandi. Ushbu kompaniya fondning institutsional cheklangan sherigi sifatida ishtirok etadi. Shuningdek, IT Park va IT Park Ventures bilan birgalikda startaplar uchun qoʻshma rivojlanish va Oʻzbekiston startaplarga birgalikda investitsiya kiritish boʻyicha Memorandum of Understanding (MoU) imzolandi.

Bu kelishuvlar Oʻrta Osiyo va MENA mintaqasi oʻrtasida ikki tomonlama koʻprik yaratishga qaratilgan. Oʻzbekiston startaplari MENA mintaqasining kapitali va bozorlariga kirish imkoniyatiga ega boʻladi, Golden Gate Ventures kompaniyasining MENA mintaqasidagi portfeli kompaniyalari esa Oʻrta Osiyoga chiqish uchun aniq yoʻlga ega boʻladi.

Fond fintech, B2B AI, e-commerce, logistika va toza energiya kabi sohalarga e’tibor qaratadi.', 'gen_images/card_stock_19473607_1781936957_1781936958.jpg', true, 13, '2026-06-20 06:29:30.500397', '@stanbasetech', 439);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (18, 'fdc71d690e2243659052473b6fc301b6', 'repost', 'Oʻzbekistonlik startap Joymee raqamli koʻchmas mulk platformasini rivojlantirish uchun navbatdagi investitsiya bosqichini yakunladi. 

Platforma foydalanuvchilarga yaqin atrofdagi koʻchmas mulk obyektlarini topish, ularni narx va joylashuviga koʻra saralash hamda mos variantlarni tez topish imkonini beradi. 

Investitsiya raundi jami $150 000 miqdorida quyidagi investorlar tomonidan amalga oshirildi: 
• AloqaVentures — $20 000
• IT Park Ventures — $50 000
• Nexus Club — $80 000', 'gen_images/card_stock_34607824_1781937993_1781937993.jpg', true, 642, '2026-06-20 06:46:38.803424', '@aloqaventures', 1417);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (19, 'c0d93f65fc09419aafe5010873aaa10a', 'repost', 'OX System startapi Turkiya va Yaqin Sharq bozorlariga kengaymoqda. 

IT Park Ventures portfelidagi startap xalqaro retail-holding Meta Mode bilan strategik hamkorlikni e’lon qildi. 2026-yil yanvar oyida OX System IT Park Ventures va United Ventures fondlaridan jami $900,000 investitsiya jalb qildi, shundan IT Park Ventures tomonidan $400,000 sarmoya kiritildi.

Bugungi kunda OX System yechimlari O‘zbekiston, Qozog‘iston, Gruziya va boshqa mamlakatlardagi 5 000 dan ortiq savdo nuqtalarida qo‘llanilmoqda. Hamkorlik doirasida holding tarkibidagi 2 000 dan ortiq savdo nuqtalari savdo jarayonlari, logistika, mijozlar ma’lumotlari va onlayn kanallarni boshqarish uchun OX System platformasiga o‘tkaziladi.

Ushbu hamkorlik OX System uchun Turkiya va Yaqin Sharq bozorlarida faoliyatini kengaytirish yo‘lida muhim qadam bo‘ldi.

@startupnews_daily', 'gen_images/card_stock_30576293_1781940674_1781940675.jpg', true, 14, '2026-06-20 07:31:23.282239', '@startupbaseuz', 8334);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (20, 'c0d93f65fc09419aafe5010873aaa10a', 'repost', 'Oʻzbekiston startap ekotizimi jadal oʻsmoqda. StartupBlink’ning 2026-yilgi Global Startup Ecosystem Index hisobotiga koʻra, mamlakatimiz startap ekotizimining yillik oʻsish sur’ati 227.3% ni tashkil etib, dunyo boʻyicha 1-oʻrinni egalladi.

<b>Oʻzbekiston</b> shu yoʻnalishda jadal rivojlanmoqda.

@startupnews_daily', 'gen_images/card_stock_16796298_1781940750_1781940751.jpg', true, 15, '2026-06-20 07:32:36.574204', '@pivotuzbekistan', 3170);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (21, 'c0d93f65fc09419aafe5010873aaa10a', 'repost', 'Oʻzbekiston va Qatar oʻrtasida sunʼiy intellekt hamda startaplar sohasida hamkorlikni rivojlantirish masalalari muhokama qilindi.

Uzbekiston raqamli texnologiyalar vaziri Sherzod Shermatov va Qatarning MBK Holding kompaniyasi asoschisi va raisi Shayx Mansur bin Xalifa Al Soniy oʻrtasidagi uchrashuvda Oʻzbekistonning IT-ekotizimi, IT Park faoliyati va texnologik sohadagi islohotlar taqdim etildi. 

Tomonlar xorijiy investitsiyalarni jalb qilish, startaplarni qoʻllab-quvvatlash va IT xizmatlari eksportini kengaytirish kabi masalalarni muhokama qildi.

<a href="https://t.me/startupnews_daily">@startupnews_daily</a>', 'gen_images/card_stock_7984735_1781980245_1781980246.jpg', true, 16, '2026-06-20 18:30:46.449683', '@pivotuzbekistan', 3176);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (22, 'fe2c49ad940043bb883395c3bbfabf61', 'psychology', '🧠 <b>Psixologiyada Motivatsiya Nazariyalari</b> 🧠

Psixologiya fanida motivatsiya nazariyalari muhim o''rin tutadi. Ular insonning xulq-atvorini, uning harakatlarini va qarorlarini tushunishga yordam beradi. 

<b>O''zbek tilida:</b>
Masalan, <b>Maslowning ehtiyojlar piramidasi</b> insonning ehtiyojlarini o''rganadi. Uning fikricha, insonning asosiy ehtiyojlari fiziologik, xavfsizlik, muhabbat, hurmat va o''z-o''zini rivojlantirishdan iborat.

<b>На русском языке:</b>
Например, <b>теория потребностей Маслоу</b> изучает потребности человека. По его мнению, основные потребности человека включают физиологические, безопасности, любви, уважения и самосовершенствования.

Psixologiyada motivatsiya nazariyalari turli xil bo''lib, ular insonning xulq-atvorini tushunishga yordam beradi. Ushbu nazariyalar orqali biz insonning ehtiyojlarini, uning harakatlarini va qarorlarini yaxshiroq tushunishimiz mumkin. 📚', '', true, 45, '2026-06-20 18:30:56.59278', NULL, NULL);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (23, 'fdc71d690e2243659052473b6fc301b6', 'repost', 'OpenAI kompaniyasi ChatGPT uchun yangi funksiyani taqdim etdi: markazlashtirilgan vazifa jadvali. Endi foydalanuvchilar barcha faol vazifalarni boshlash vaqtlari va boshqarish tugmalari bilan koʻra oladilar. Vazifalar uchun aniq vaqtlar yoki "ertalab" yoki "kechqurun" kabi umumiy davrlar belgilash mumkin.

ChatGPT tanlangan veb-saytlar va ulangan ilovalarni oʻzgarishlar uchun kuzatib boradi va foydalanuvchilarni xabardor qiladi. Bu Pulse kundalik xabarlar xususiyatining oʻrnini bosadi. Yangilanish Plus, Pro, Business va Enterprise tarif rejalari uchun mavjud.

@OxunjonCommunity', 'gen_images/card_stock_16245252_1781980287_1781980288.jpg', true, 647, '2026-06-20 18:31:28.254458', '@tech', 3543);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (24, 'c0d93f65fc09419aafe5010873aaa10a', 'repost', 'ChatGPT tibbiy aniqlikda shifokorlardan oʻzib ketdi

OpenAI kompaniyasi ChatGPT endi tibbiy savollarga ikki oy ichida 71% kamroq xatolar bilan javob berishini maʼlum qildi. Bu yaxshilanish 60 ta davlatdagi 260 nafar shifokor tomonidan 700,000 ta javoblarning qoʻlda koʻrib chiqilishi natijasida erishildi.

ChatGPT GPT-5.5 Instant tomonidan quvvatlanadi, bu foydalanuvchilar uchun bepul. U haftalik 230 million sogʻliqni saqlash savollariga ishlov beradi, ammo aniqlik testlari ichki ravishda oʻtkazildi va mustaqil klinik tasdiqlash oʻtkazilmadi.

@startupnews_daily', 'gen_images/card_stock_16037279_1782036427_1782036428.jpg', true, 17, '2026-06-21 10:07:35.964019', '@tech', 3547);
INSERT INTO public.posts_history (id, tenant_id, topic, content, image_path, posted, message_id, created_at, source_chat_id, source_message_id) VALUES (25, 'fdc71d690e2243659052473b6fc301b6', 'repost', 'Codex kompaniyasi Record & Replay funksiyasini taqdim etdi. Bu funksiya yordamida foydalanuvchilar agentga kompyuterda vazifalarni bajarishni bir marta koʻrsatish orqali oʻrgatishi mumkin.

Agent videolarni YouTubeʼga yuklash, fotosuratlarni tahrirlash yoki hujjatlarni imzolash kabi ketma-ketliklarni oʻrganadi va ularni avtomatik ravishda takrorlaydi.

Funksiya Codex ilovasi foydalanuvchilarga bosqichma-bosqich tarqatilmoqda. @OxunjonCommunity', 'gen_images/card_stock_30727762_1782036579_1782036580.jpg', true, 648, '2026-06-21 10:09:51.122928', '@tech', 3544);


