INSERT INTO public.tenant_profiles (id, tenant_id, chat_id, channel_name, tone, language, writing_style, audience, post_template, image_style, topics, subscription_tier, avg_post_length, creativity_level, factual_strictness, active, created_at, updated_at, owner_id, schedule_mode, posts_per_day, post_times, cta, use_rag, use_references, content_mode) VALUES (4, 'c0d93f65fc09419aafe5010873aaa10a', '-1003782829887', 'startup news', 'neutral', 'uz', '', '', NULL, 'Cinematic dramatic premium poster illustration, luxurious and high-end. Deep navy-blue gradient background with subtle geometric tech line patterns and atmospheric haze. A lone businessman founder silhouette standing on a stage at a podium under a powerful volumetric spotlight beam shining down from above, facing a large audience of silhouetted people in a dark auditorium. Glowing golden 3D metallic accents, warm gold light rays and lens flare against the cold deep-blue scene, rich gold-and-blue color palette, very high contrast, moody dramatic lighting, photorealistic cinematic 3D render, professional startup venture-capital and finance mood, sense of ambition opportunity and success. No text, no letters, no numbers, no logos, no watermarks. Cinematic visual metaphor of: {subject}', 'startup, investments, projects, IT, bussiness', 'starter', 0, 0.5, 0.7, true, '2026-06-19 08:19:11.706284', '2026-06-20 07:32:47.937886', NULL, 'frequency', 5, '09:00', '@startupnews_daily', false, true, 'repost');
INSERT INTO public.tenant_profiles (id, tenant_id, chat_id, channel_name, tone, language, writing_style, audience, post_template, image_style, topics, subscription_tier, avg_post_length, creativity_level, factual_strictness, active, created_at, updated_at, owner_id, schedule_mode, posts_per_day, post_times, cta, use_rag, use_references, content_mode) VALUES (1, 'fe2c49ad940043bb883395c3bbfabf61', '@interstudy_journal', 'INTER STUDY | IS', 'informative, inviting', 'uz, ru', 'Concise and informative, using emojis and lists for clarity and engagement.', 'academics, researchers, students, and educators interested in publishing or consuming academic content', NULL, NULL, 'academic publishing, psychology, pedagogy, scientific facts, humanities, technology', 'starter', 388, 0.5, 0.7, true, '2026-06-17 18:47:47.314491', '2026-06-17 20:35:55.187339', '8489603882', 'off', 0, '', '', true, true, 'topic');
INSERT INTO public.tenant_profiles (id, tenant_id, chat_id, channel_name, tone, language, writing_style, audience, post_template, image_style, topics, subscription_tier, avg_post_length, creativity_level, factual_strictness, active, created_at, updated_at, owner_id, schedule_mode, posts_per_day, post_times, cta, use_rag, use_references, content_mode) VALUES (2, 'e52c41790f9e4a389802b0d856ec9612', '@ieandgs', 'INTER EDUCATION & GLOBAL STUDY', 'Informative, promotional', 'uz, ru', 'Uses a mix of short and medium sentences, frequently incorporates relevant emojis, and often structures information with bullet points or clear sections.', 'Academics, researchers, educators, and students in humanities and social sciences, particularly in Uzbekistan.', NULL, NULL, 'Academic journal calls for papers, pedagogy, psychology, art history, historical landmarks, educational research, artificial intelligence in education', 'starter', 388, 0.5, 0.7, true, '2026-06-17 18:54:29.746922', '2026-06-17 18:54:38.029167', NULL, 'off', 0, '', '', true, true, 'topic');
INSERT INTO public.tenant_profiles (id, tenant_id, chat_id, channel_name, tone, language, writing_style, audience, post_template, image_style, topics, subscription_tier, avg_post_length, creativity_level, factual_strictness, active, created_at, updated_at, owner_id, schedule_mode, posts_per_day, post_times, cta, use_rag, use_references, content_mode) VALUES (3, 'fdc71d690e2243659052473b6fc301b6', '@oxunjoncommunity', 'Oxunjon Community | Startuplarda vakansiya', 'enthusiastic and encouraging', 'uz', 'Conversational and informal, using a mix of short, punchy sentences and longer descriptive paragraphs, with frequent use of emojis and clear calls to action.', 'Startup founders, aspiring entrepreneurs, developers, investors, and professionals interested in the tech and startup ecosystem in Uzbekistan.', NULL, 'Cinematic dramatic premium poster illustration, luxurious and high-end. Deep navy-blue gradient background with subtle geometric tech line patterns and atmospheric haze. A lone businessman founder silhouette standing on a stage at a podium under a powerful volumetric spotlight beam shining down from above, facing a large audience of silhouetted people in a dark auditorium. Glowing golden 3D metallic accents, warm gold light rays and lens flare against the cold deep-blue scene, rich gold-and-blue color palette, very high contrast, moody dramatic lighting, photorealistic cinematic 3D render, professional startup venture-capital and finance mood, sense of ambition opportunity and success. No text, no letters, no numbers, no logos, no watermarks. Cinematic visual metaphor of: {subject}', 'startup development, investment and funding, entrepreneurial events, networking, digital product promotion, personal development', 'starter', 131, 0.6, 0.75, true, '2026-06-17 19:19:56.123431', '2026-06-20 07:24:36.4405', '8192361257', 'times', 1, '10:00', '@OxunjonCommunity', false, true, 'repost');


